// // This module is designed to implement a 4-bit shift register with a clock input (clk), a reset input (rst), a serial data input (s_in), and a 4-bit parallel output (q). However, the actual functionality of this module is to perform a bitwise AND operation between the current state of the shift register and the serial input data on each clock edge.
module shift_register4bit(
	input clk,
	input rst,
	input s_in,
	output reg [3:0] q);

	always @(posedge clk or posedge rst) begin
		if (rst)
			q <= 4'b0000;
		else
			q <= {q[2:0], s_in};
	end

endmodule
